// 1. 🚨 核心修复：不要用 $input，直接从【源头 Webhook 节点】强行抓取数据！
// 无视中间经过的 HTTP 请求节点，确保拿到最原始的参数。
const webhookJson = $('Webhook').first()?.json || {};
const body = webhookJson.body || {};

// 2. 辅助函数：安全转换字符串
function toText(v) {
  if (v == null) return '';
  if (typeof v === 'object') return String(v.text ?? v.value ?? v.name ?? '').trim();
  return String(v).trim();
}

function pickMeta(...keys) {
  for (const key of keys) {
    const value = body.metadata?.[key];
    const text = toText(value);
    if (text) return text;
  }
  return '';
}

function normalizeContentType(raw, hasProduct) {
  const value = toText(raw).toLowerCase();
  if (['story', 'plot', 'narrative', '剧情', '剧情视频'].includes(value)) return 'story';
  if (['commerce', 'product', 'shopping', '带货', '带货视频'].includes(value)) return 'commerce';
  return hasProduct ? 'commerce' : 'story';
}

function normalizeStoryType(raw, label) {
  const value = toText(raw || label).toLowerCase();
  if (value.includes('body') || value.includes('science') || value.includes('身体')) return '身体科学型';
  if (value.includes('survival') || value.includes('challenge') || value.includes('生存')) return '生存挑战型';
  if (value.includes('hypothetical') || value.includes('假设')) return '假设情景型';
  if (value.includes('growth') || value.includes('age') || value.includes('成长')) return '人生成长型';
  return label || '时间推进型';
}

// 3. 针对 Agent 需求的精准字段映射
// 提取产品名称
const productName = toText(body.product_name || body.productName || "");

// 提取产品描述：优先取最详细的卖点字段
const productDesc = toText(body.product_selling_points || body.product_description || "");

const contentType = normalizeContentType(
  body.content_type || body.contentType || body.video_type || body.videoType || pickMeta('content_type', 'contentType', 'video_type', 'videoType'),
  Boolean(productName || body.product_id || body.productId)
);

// 提取角色与模式
const presenterMode = toText(body.metadata?.feature || 'skeleton_storyboard');
const personDesc = toText(body.character_name || body.characterName || '3D透明骨骼');
const storySubject = toText(body.story_subject || body.storySubject || pickMeta('story_subject', 'storySubject') || personDesc || 'transparent skeleton character');
const storyScene = toText(body.story_scene || body.storyScene || pickMeta('story_scene', 'storyScene') || '一个强反差的电影感场景');
const storyTypeLabel = toText(body.story_type_label || body.storyTypeLabel || pickMeta('story_type_label', 'storyTypeLabel'));
const storyType = normalizeStoryType(body.story_type || body.storyType || pickMeta('story_type', 'storyType'), storyTypeLabel);

// 提取时长与分段逻辑
const durationSec = parseInt(body.duration_sec || body.metadata?.duration_sec || body.duration_seconds || 64);
const segSeconds = 8;
const nSegments = Math.ceil(durationSec / segSeconds);

const language = toText(body.language || body.target_language || body.metadata?.target_language || (contentType === 'story' ? 'en' : 'auto'));
const viralScriptSummaryRaw = toText(body.script || body.script_content || 'N/A');

// 4. 返回平铺后的标准数据
return [{
  json: {
    ...body, // 保留 body 原始字段供下游其他节点直接调用
    contentType,
    content_type: contentType,
    videoType: contentType,
    video_type: contentType,
    productName,
    productDesc,
    presenterMode,
    personDesc,
    storySubject,
    story_subject: storySubject,
    storyScene,
    story_scene: storyScene,
    storyType,
    story_type: storyType,
    storyTypeLabel: storyTypeLabel || storyType,
    story_type_label: storyTypeLabel || storyType,
    durationSec,
    nSegments,
    segSeconds,
    language,
    viralScriptSummaryRaw,
    // 基础 ID 类参数
    task_id: body.task_id || body.taskId || "",
    admin_token: body.admin_token || body.adminToken || "",
    callback_url: body.callback_url || body.callbackUrl || ""
  }
}];

function stripFences(s) { return String(s || '').trim().replace(/^```[a-zA-Z]*\n?/, '').replace(/```$/, '').trim(); }
function safeParse(s) { try { return JSON.parse(s); } catch { return null; } }
function pickRawText(in0) {
  if (!in0) return '';
  if (typeof in0 === 'object' && in0.shots && Array.isArray(in0.shots)) return in0;
  return in0.output || in0.text || in0.response || in0?.candidates?.[0]?.content?.parts?.[0]?.text || '';
}
function extractFirstJsonObject(str) {
  const s = String(str || '');
  const i = s.indexOf('{'), j = s.lastIndexOf('}');
  return (i < 0 || j <= i) ? null : s.slice(i, j + 1);
}
function toBool(v) {
  const t = String(v == null ? '' : v).trim().toLowerCase();
  if (['1','true','yes','y','是','有'].includes(t)) return true;
  if (['0','false','no','n','否','无'].includes(t)) return false;
  return null;
}
function toText(v) {
  if (v == null) return '';
  if (Array.isArray(v)) return v.map((x) => toText(x)).filter(Boolean).join('\n').trim();
  if (typeof v === 'object') return String(v.text ?? v.value ?? v.name ?? '').trim();
  return String(v).trim();
}

const in0 = $input.first()?.json || {};
let raw = pickRawText(in0);
let obj = raw && typeof raw === 'object' && Array.isArray(raw.shots) ? raw : safeParse(extractFirstJsonObject(stripFences(raw)));
if (!obj || !Array.isArray(obj.shots)) throw new Error('JSON Parse failed or no shots array.');

const root = $('标准化输入').first()?.json || {};
const AI达人 = toText(root['AI达人'] || root.ai_creator || root.creatorName || '');
const 产品名称 = toText(root.productName || root.product_name || root['产品名称'] || '');
const task_id = toText(root.task_id || root.record_id || root.recordId || '');
const callback_url = toText(root.callback_url || root.callbackUrl || '');
const admin_token = toText(root.admin_token || root.adminToken || '');
const pipeline_key = toText(root.pipeline_key || root.pipelineKey || 'skeleton_video');
const workflow_id = toText(root.workflow_id || root.workflowId || '');
const workflow_name = toText(root.workflow_name || root.workflowName || '');

const shots = obj.shots.map((s, idx) => ({
  idx: s.shot_number || s.idx || s.order || idx + 1,
  shot_number: s.shot_number || idx + 1,
  timestamp: s.timestamp || '',
  time_range: s.timestamp || s.time_range || s.timeRange || '',
  duration_seconds: s.duration_seconds || s.duration || 8,
  duration: s.duration_seconds || s.duration || 8,
  voiceover: String(s.voiceover || s.speech || s.text || ''),
  action: String(s.action || ''),
  first_frame: String(s.first_frame || s.image_prompt || '').replace(/[\r\n]+/g, ' ').trim(),
  video_prompt: String(s.video_prompt || s.videoPrompt || '').replace(/[\r\n]+/g, ' ').trim(),
  has_product: toBool(s['是否有产品'] ?? s.has_product ?? s.hasProduct),
  '是否有产品': toBool(s['是否有产品'] ?? s.has_product ?? s.hasProduct),
  AI达人,
  产品名称,
}));

return [{ json: {
  task_id,
  callback_url,
  admin_token,
  pipeline_key,
  workflow_id,
  workflow_name,
  total_shots: shots.length,
  shots,
}}];

